package com.test.webhooks;
 
import java.io.File;
import java.util.Map;
 
import javax.servlet.http.HttpServletRequest;
 
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpMethod;
import org.springframework.stereotype.Component;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.HttpMessageNotReadableException;
import org.springframework.web.client.RestTemplate;
 
@Component
public class CustomWebHookHandler {
 
 
	@Autowired
	private RestTemplate restTemplate;
 
	public String handleRequest(Map<String, String> requestParameters, HttpServletRequest httpRequest) throws Exception{
		
		File file = new File(httpRequest.getScheme() + "://" + httpRequest.getServerName() + ":" + httpRequest.getServerPort() + httpRequest.getRequestURI());
 
		String contentType;
 		
		switch (file.getName()) {
			case "sample.txt":
				contentType="application/x-www-form-urlencoded";
				break;
			
			default:
				return null;
			
		}		
		
		String url = httpRequest.getScheme() + "://" + httpRequest.getServerName()+":"+httpRequest.getServerPort()+"/sample";
		try {
			System.out.println("restTemplate call started");
			restTemplate.exchange(url, HttpMethod.POST, null, String.class);
			return "success";
			
		} catch (HttpClientErrorException | HttpMessageNotReadableException e) {
			// TODO Auto-generated catch block
			e.printStackTrace();
		}
		
		
		return contentType;
	}
}